      <motion.p {...revealUp} className="[word-break:break-word] absolute font-['Inter_Tight:Regular',sans-serif] leading-[1.25] left-[calc(50%+328.3px)] not-italic text-text-secondary text-[16.885px] top-[12317px] w-[440px]">{`The Company Keyboard reads rhythm, pace, and interaction patterns. It has no access to the content of what you write. That's a technical boundary, not just a policy.`}</motion.p>
